// src/pages/Leave/LeavePage.js
import React, { useState, useEffect, useCallback } from 'react';
import {
  CalendarDays, Plus, Check, X, Clock, AlertCircle,
  Send, BarChart2, Calendar, Edit3, Users, Settings,
  RefreshCw, ArrowRightLeft, Shield
} from 'lucide-react';
import toast from 'react-hot-toast';
import { leaveAPI, notificationAPI } from '../../api/services';
import { Modal, Badge, SkeletonCard, InlineSpinner } from '../../components/common';
import { useAuth } from '../../context/AuthContext';

const STATUS_LABEL = {
  SUBMITTED: 'Submitted', PENDING_MANAGER: 'Pending Approval',
  PendingManager: 'Pending Approval', PENDING_HR: 'Pending HR',
  APPROVED: 'Approved', REJECTED: 'Rejected', CANCELLED: 'Cancelled',
  DRAFT: 'Draft', Submitted: 'Submitted', Pending: 'Pending Approval',
  Approved: 'Approved', Rejected: 'Rejected', Cancelled: 'Cancelled',
};

const STATUS_OPTIONS = [
  { value: '', label: 'All' },
  { value: 'SUBMITTED', label: 'Submitted' },
  { value: 'PENDING_MANAGER', label: 'Pending Approval' },
  { value: 'APPROVED', label: 'Approved' },
  { value: 'REJECTED', label: 'Rejected' },
  { value: 'CANCELLED', label: 'Cancelled' },
];

const STATUS_HISTORY = [
  { value: '', label: 'All' },
  { value: 'SUBMITTED', label: 'Submitted' },
  { value: 'PENDING_MANAGER', label: 'Pending' },
  { value: 'APPROVED', label: 'Approved' },
  { value: 'REJECTED', label: 'Rejected' },
  { value: 'CANCELLED', label: 'Cancelled' },
];

const normStatus = s => (s || '').toUpperCase().replace(/_/g, '');
const statusMatches = (reqStatus, filterValue) => {
  if (!filterValue) return true;
  const rs = normStatus(reqStatus);
  const fv = normStatus(filterValue);
  if (rs === fv) return true;
  const allPending = new Set(['PENDINGMANAGER','PENDINGHR','SUBMITTED','PENDING','DRAFT']);
  if (fv === 'PENDINGMANAGER' && allPending.has(rs)) return true;
  return false;
};
const isFinalStatus = s => ['APPROVED','REJECTED','CANCELLED'].includes(normStatus(s));

// Extracts arrays safely from all backend envelopes
const toArr = (r) => {
  if (!r) return [];
  const d = r.data || r;
  if (Array.isArray(d)) return d;
  if (Array.isArray(d?.requests)) return d.requests;
  if (d?.data && Array.isArray(d.data)) return d.data;
  if (d?.data?.requests && Array.isArray(d.data.requests)) return d.data.requests;
  return [];
};

function BalanceCard({ balance, loading }) {
  if (loading) return <SkeletonCard />;
  const name = balance.leaveTypeName || balance.LeaveTypeName || balance.LeaveType?.LeaveTypeName || 'Leave';
  const used = Number(balance.usedDays ?? balance.UsedDays ?? 0);
  const pending = Number(balance.pendingDays ?? balance.PendingDays ?? 0);
  const entitled = Number(balance.entitledDays ?? balance.EntitledDays ?? 0);
  const carryOver = Number(balance.carryOverDays ?? balance.CarryOverDays ?? 0);
  const adjusted = Number(balance.adjustedDays ?? balance.AdjustedDays ?? 0);
  const remaining = Number(balance.remainingDays ?? balance.RemainingDays ?? Math.max(0, entitled + carryOver + adjusted - used - pending));
  const maxDays = Number(balance.maxDaysPerYear ?? (entitled + carryOver + adjusted));
  const total = maxDays || (used + remaining) || 1;
  const pct = total > 0 ? Math.round((remaining / total) * 100) : 0;

  const color = name.includes('Sick') || name.includes('Medical') ? 'var(--green)' : 
                name.includes('Emergency') ? 'var(--red)' : 'var(--blue)';

  return (
    <div className="stat-card">
      <div className="stat-card-accent" style={{ background: color }} />
      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 12 }}>
        <div style={{ fontSize: '0.78rem', color: 'var(--text-secondary)', fontWeight: 500, textTransform: 'uppercase' }}>{name}</div>
        <CalendarDays size={18} style={{ color }} />
      </div>
      <div className="stat-card-value" style={{ color }}>{remaining}</div>
      <div className="stat-card-label">days remaining of {maxDays}</div>
      <div className="stat-card-progress" style={{ marginTop: 12 }}><div className="stat-card-progress-bar" style={{ width: `${pct}%`, background: color }} /></div>
      <div className="stat-card-meta"><span>{used} used {pending > 0 && `· ${pending} pending`}</span><span>{pct}%</span></div>
    </div>
  );
}

function RequestRow({ req, onAction, onEdit, isManager, isHR }) {
  const [acting, setActing] = useState('');
  const name = req.LeaveType?.LeaveTypeName || req.leaveType?.LeaveTypeName || req.LeaveTypeName || '—';
  const from = (req.StartDate || req.startDate) ? new Date(req.StartDate || req.startDate).toLocaleDateString() : '—';
  const to = (req.EndDate || req.endDate) ? new Date(req.EndDate || req.endDate).toLocaleDateString() : '—';
  const days = req.TotalDays ?? req.totalDays ?? '—';
  const status = req.Status || req.status || 'SUBMITTED';
  const id = req.LeaveRequestID || req.id;
  const empName = req.Employee?.FullName || req.employeeName || '—';

  const act = async (action) => {
    setActing(action);
    try { await onAction(id, action); } finally { setActing(''); }
  };

  const isFinal = isFinalStatus(status);

  return (
    <tr>
      <td><div style={{ fontWeight: 500 }}>{name}</div><div style={{ fontSize: '0.75rem', color: 'var(--text-secondary)' }}>{req.Reason || req.reason}</div></td>
      {isManager && <td><div style={{ fontWeight: 500 }}>{empName}</div></td>}
      <td style={{ fontSize: '0.82rem' }}>{from} → {to}</td>
      <td>{days}</td>
      <td>
        <span style={{
          display: 'inline-block', padding: '3px 10px', borderRadius: 20, fontSize: '0.75rem', fontWeight: 600,
          background: normStatus(status) === 'APPROVED' ? 'rgba(34,197,94,0.15)' : normStatus(status) === 'REJECTED' ? 'rgba(239,68,68,0.15)' : 'rgba(251,191,36,0.15)',
          color: normStatus(status) === 'APPROVED' ? '#16a34a' : normStatus(status) === 'REJECTED' ? '#dc2626' : '#b45309',
        }}>{STATUS_LABEL[status] || status}</span>
      </td>
      <td>
        <div style={{ display: 'flex', gap: 6 }}>
          {isManager && !isFinal && (
            <>
              <button className="btn btn-success btn-sm" onClick={() => act('approve')} disabled={!!acting}>{acting === 'approve' ? <InlineSpinner /> : 'Approve'}</button>
              <button className="btn btn-danger btn-sm" onClick={() => act('reject')} disabled={!!acting}>{acting === 'reject' ? <InlineSpinner /> : 'Reject'}</button>
            </>
          )}
          {isHR && isFinal && normStatus(status) !== 'CANCELLED' && (
            <button className="btn btn-ghost btn-sm" onClick={() => act(normStatus(status) === 'APPROVED' ? 'reject' : 'approve')} disabled={!!acting}><Shield size={13} style={{marginRight: 4}}/> Override</button>
          )}
          {!isManager && !isFinal && (
            <>
              {onEdit && <button className="btn btn-ghost btn-sm" onClick={() => onEdit(req)}><Edit3 size={14} /> Edit</button>}
              <button className="btn btn-ghost btn-sm" onClick={() => act('cancel')} disabled={!!acting}>{acting === 'cancel' ? <InlineSpinner /> : 'Cancel'}</button>
            </>
          )}
        </div>
      </td>
    </tr>
  );
}

// ─── RESTORED ORIGINAL SUBMIT FORM ──────────────────────────────────────────
function SubmitLeaveForm({ leaveTypes, onSubmit, loading }) {
  const [form, setForm] = useState({ LeaveTypeID: '', startDate: '', endDate: '', reason: '', isHalfDay: false, documentReference: '' });
  const [errors, setErrors] = useState({});
  const set = (k, v) => { setForm(f => ({ ...f, [k]: v })); setErrors(e => ({ ...e, [k]: '' })); };

  const validate = () => {
    const e = {};
    if (!form.LeaveTypeID) e.LeaveTypeID = 'Select a leave type';
    if (!form.startDate)   e.startDate   = 'Required';
    if (!form.endDate)     e.endDate     = 'Required';
    if (form.startDate && form.endDate && form.endDate < form.startDate)
      e.endDate = 'End date must be after start date';
    return e;
  };

  const handle = () => {
    const e = validate();
    if (Object.keys(e).length) { setErrors(e); return; }

    // Exact matching for backend submitLeaveRequestSchema
    onSubmit({
      LeaveTypeID: parseInt(form.LeaveTypeID, 10),
      StartDate: new Date(form.startDate).toISOString(),
      EndDate: new Date(form.endDate).toISOString(),
      IsHalfDay: form.isHalfDay,
      Reason: form.reason || null,
      DocumentReference: form.documentReference || null
    });
  };

  const days = form.startDate && form.endDate
    ? Math.max(0, Math.round((new Date(form.endDate) - new Date(form.startDate)) / 86400000) + 1)
    : 0;

  return (
    <>
      <div style={{ display: 'flex', alignItems: 'center', gap: 4, marginBottom: 20 }}>
        {[{l:'Leave Type',done:!!form.LeaveTypeID},{l:'Dates',done:!!(form.startDate&&form.endDate)},{l:'Details',done:false}].map((s,i,arr) => (
          <React.Fragment key={i}>
            <div style={{ display:'flex', alignItems:'center', gap:5, fontSize:'0.75rem',
              color: s.done ? '#16a34a' : 'var(--text-secondary)', fontWeight: s.done ? 600 : 400 }}>
              <span style={{ width:18, height:18, borderRadius:'50%', display:'inline-flex', alignItems:'center',
                justifyContent:'center', fontSize:'0.6rem', fontWeight:700,
                background: s.done ? 'rgba(34,197,94,0.15)' : 'var(--surface-alt,#2a2a3a)',
                color: s.done ? '#16a34a' : 'var(--text-muted)', border:'1px solid', borderColor: s.done ? 'rgba(34,197,94,0.4)':'var(--border)' }}>
                {s.done ? '✓' : i+1}
              </span>
              {s.l}
            </div>
            {i < arr.length-1 && <span style={{flex:1, height:1, background:'var(--border)', margin:'0 4px'}} />}
          </React.Fragment>
        ))}
      </div>

      <div className="form-group"><label className="form-label required">Leave Type</label>
        <select className="form-select" value={form.LeaveTypeID} onChange={e => set('LeaveTypeID', e.target.value)}>
          <option value="">— Select a leave type —</option>
          {leaveTypes.map(t => <option key={t.LeaveTypeID} value={t.LeaveTypeID}>{t.LeaveTypeName}</option>)}
        </select>
        {errors.LeaveTypeID && <div className="form-error">{errors.LeaveTypeID}</div>}
      </div>

      <div className="form-row">
        <div className="form-group"><label className="form-label required">Start Date</label>
          <input className="form-input" type="date" value={form.startDate} min={new Date().toISOString().split('T')[0]} onChange={e => set('startDate', e.target.value)} />
          {errors.startDate && <div className="form-error">{errors.startDate}</div>}
        </div>
        <div className="form-group"><label className="form-label required">End Date</label>
          <input className="form-input" type="date" value={form.endDate} min={form.startDate || new Date().toISOString().split('T')[0]} onChange={e => set('endDate', e.target.value)} />
          {errors.endDate && <div className="form-error">{errors.endDate}</div>}
        </div>
      </div>

      {days > 0 && (
        <div style={{ padding:'10px 14px', background:'rgba(34,197,94,0.07)', border:'1px solid rgba(34,197,94,0.2)', borderRadius:'var(--radius-md)', marginBottom:14, fontSize:'0.85rem', color:'#16a34a', fontWeight:500 }}>
          📅 <strong>{days} calendar day{days!==1?'s':''}</strong>
        </div>
      )}

      <div className="form-group">
        <label style={{display:'flex',alignItems:'center',gap:8,cursor:'pointer',fontSize:'0.875rem',userSelect:'none'}}>
          <input type="checkbox" checked={form.isHalfDay} onChange={e => set('isHalfDay', e.target.checked)} />
          <span>Half-day <span style={{color:'var(--text-secondary)',fontSize:'0.78rem'}}>(0.5 days deducted)</span></span>
        </label>
      </div>

      <div className="form-group">
        <label className="form-label">Reason <span style={{color:'var(--text-secondary)',fontSize:'0.76rem',fontWeight:400,marginLeft:6}}>optional</span></label>
        <textarea className="form-textarea" rows={2} value={form.reason} onChange={e => set('reason', e.target.value)} placeholder="Briefly describe the reason for this leave request..." />
      </div>

      <div className="form-group">
        <label className="form-label">Document Reference <span style={{color:'var(--text-secondary)',fontSize:'0.76rem',fontWeight:400,marginLeft:6}}>required for sick &gt;1 day · maternity</span></label>
        <input className="form-input" type="text" value={form.documentReference} onChange={e => set('documentReference', e.target.value)} placeholder="Medical cert no. …" />
      </div>

      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center', marginTop:16, paddingTop:14, borderTop:'1px solid var(--border-light)'}}>
        <button className="btn btn-ghost" type="button" onClick={() => { setForm({LeaveTypeID:'',startDate:'',endDate:'',reason:'',isHalfDay:false,documentReference:''}); setErrors({}); }} disabled={loading}>Clear form</button>
        <button className="btn btn-primary" onClick={handle} disabled={loading||!form.LeaveTypeID||!form.startDate||!form.endDate}>{loading ? <InlineSpinner /> : <><Send size={15} style={{marginRight:6}}/>Submit Request</>}</button>
      </div>
    </>
  );
}

// ─── RESTORED ORIGINAL EDIT MODAL ──────────────────────────────────────────
function EditRequestModal({ req, leaveTypes, onSave, onClose, loading }) {
  const [form, setForm] = useState({
    startDate: (req.StartDate || req.startDate || '').split('T')[0],
    endDate:   (req.EndDate   || req.endDate   || '').split('T')[0],
    reason:    req.Reason     || req.reason    || '',
    documentReference: req.DocumentReference || req.documentReference || '',
    LeaveTypeID: req.LeaveTypeID || req.leaveTypeId || '',
  });

  const handleSave = () => {
    // Exact matching for backend updateLeaveRequestSchema
    onSave({
      LeaveTypeID: form.LeaveTypeID ? parseInt(form.LeaveTypeID, 10) : undefined,
      StartDate: new Date(form.startDate).toISOString(),
      EndDate: new Date(form.endDate).toISOString(),
      Reason: form.reason || null,
      DocumentReference: form.documentReference || null
    });
  };

  return (
    <Modal title="Edit Leave Request" onClose={onClose}>
      <div className="form-group">
        <label className="form-label">Leave Type</label>
        <select className="form-select" value={form.LeaveTypeID} onChange={e => setForm({...form, LeaveTypeID: e.target.value})}>
          <option value="">— Keep current —</option>
          {leaveTypes.map(t => <option key={t.LeaveTypeID || t.id} value={t.LeaveTypeID || t.id}>{t.LeaveTypeName || t.name}</option>)}
        </select>
      </div>
      <div className="form-row">
        <div className="form-group"><label className="form-label required">Start Date</label><input className="form-input" type="date" value={form.startDate} onChange={e => setForm({...form, startDate: e.target.value})} /></div>
        <div className="form-group"><label className="form-label required">End Date</label><input className="form-input" type="date" value={form.endDate} min={form.startDate} onChange={e => setForm({...form, endDate: e.target.value})} /></div>
      </div>
      <div className="form-group"><label className="form-label">Reason</label><textarea className="form-textarea" rows={2} value={form.reason} onChange={e => setForm({...form, reason: e.target.value})} /></div>
      <div className="form-group"><label className="form-label">Document Reference</label><input className="form-input" type="text" value={form.documentReference} onChange={e => setForm({...form, documentReference: e.target.value})} /></div>
      <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10 }}>
        <button className="btn btn-ghost" onClick={onClose} disabled={loading}>Cancel</button>
        <button className="btn btn-primary" onClick={handleSave} disabled={loading || !form.startDate || !form.endDate}>{loading ? <InlineSpinner /> : 'Save Changes'}</button>
      </div>
    </Modal>
  );
}

function ReasonModal({ title, placeholder, onConfirm, onClose, loading }) {
  const [reason, setReason] = useState('');
  return (
    <Modal title={title} onClose={onClose}>
      <div className="form-group"><label className="form-label required">Reason</label><textarea className="form-textarea" value={reason} onChange={e => setReason(e.target.value)} placeholder={placeholder} rows={3} /></div>
      <div style={{ display: 'flex', justifyContent: 'flex-end', gap: 10 }}>
        <button className="btn btn-ghost" onClick={onClose} disabled={loading}>Back</button>
        <button className="btn btn-primary" onClick={() => reason.trim() && onConfirm(reason.trim())} disabled={loading || !reason.trim()}>{loading ? <InlineSpinner /> : 'Confirm'}</button>
      </div>
    </Modal>
  );
}

// ─── OVERRIDE PANEL ────────────────────────────────────────────────────────
function OverridePanel({ requests, onOverride }) {
  const [selected, setSelected] = useState('');
  const [newStatus, setNewStatus] = useState('APPROVED');
  const [reason, setReason] = useState('');

  return (
    <div className="card" style={{ marginBottom: 16 }}>
      <div className="card-header"><div className="card-title"><Shield size={15} style={{ marginRight: 6 }} />Override Manager Decision</div></div>
      <div className="form-group">
        <label className="form-label">Select Request</label>
        <select className="form-select" value={selected} onChange={e => setSelected(e.target.value)}>
          <option value="">— Select a finalized request —</option>
          {requests.filter(r => isFinalStatus(r.Status || r.status)).map(r => (
            <option key={r.LeaveRequestID || r.id} value={r.LeaveRequestID || r.id}>{r.Employee?.FullName || 'Employee'} — {r.Status || r.status}</option>
          ))}
        </select>
      </div>
      <div className="form-row">
        <div className="form-group">
          <label className="form-label">Override To</label>
          <select className="form-select" value={newStatus} onChange={e => setNewStatus(e.target.value)}>
            <option value="APPROVED">Approved</option>
            <option value="REJECTED">Rejected</option>
          </select>
        </div>
      </div>
      <div className="form-group">
        <label className="form-label required">Override Reason</label>
        <textarea className="form-textarea" rows={2} value={reason} onChange={e => setReason(e.target.value)} />
      </div>
      <button className="btn btn-primary btn-sm" disabled={!selected || !reason.trim()} onClick={() => { onOverride(selected, newStatus, reason); setSelected(''); setReason(''); }}>Apply Override</button>
    </div>
  );
}

// ─── DELEGATION PANEL ──────────────────────────────────────────────────────
function DelegationPanel({ onDelegate }) {
  const [delegateTo, setDelegateTo] = useState('');
  const [until, setUntil] = useState('');

  const handleActivate = () => {
    // FIXED: Joi schema expects exactly { delegateTo: number, comments: string }
    onDelegate(1, { 
      delegateTo: parseInt(delegateTo, 10), 
      comments: `Delegated until ${until}` 
    });
  };

  return (
    <div className="card" style={{ marginBottom: 16 }}>
      <div className="card-header"><div className="card-title"><Users size={15} style={{ marginRight: 6 }} />Approval Delegation</div></div>
      <div className="form-row">
        <div className="form-group"><label className="form-label">Delegate To (Employee ID)</label><input className="form-input" type="number" value={delegateTo} onChange={e => setDelegateTo(e.target.value)} /></div>
        <div className="form-group"><label className="form-label">Delegate Until</label><input className="form-input" type="date" value={until} onChange={e => setUntil(e.target.value)} /></div>
      </div>
      <button className="btn btn-primary btn-sm" disabled={!delegateTo || !until} onClick={handleActivate}>Activate Delegation</button>
    </div>
  );
}

// ─── MAIN PAGE ─────────────────────────────────────────────────────────────
export default function LeavePage() {
  const { user }  = useAuth();
  const roleStr = (user?.role || user?.Role || '').toUpperCase();
  const isManager = roleStr.includes('MANAGER') || roleStr.includes('HR') || roleStr.includes('ADMIN') || roleStr === 'SUPERVISOR';
  const isHR = roleStr.includes('HR') || roleStr.includes('ADMIN');

  const [tab, setTab] = useState('dashboard');
  const [balances, setBalances] = useState([]);
  const [myRequests, setMyReqs] = useState([]);
  const [allRequests, setAll] = useState([]);
  const [leaveTypes, setTypes] = useState([]);

  const [loadBal, setLoadBal] = useState(true);
  const [loadReq, setLoadReq] = useState(true);
  const [loadAll, setLoadAll] = useState(true);

  const [submitting, setSubmitting] = useState(false);
  const [historyFilter, setHistoryFilter] = useState('');
  const [allFilter, setAllFilter] = useState('');
  const [reasonModal, setReasonModal] = useState(null); 
  const [actingReason, setActingReason] = useState(false);
  const [editingRequest, setEditingRequest] = useState(null);
  const [isSubmitModalOpen, setIsSubmitModalOpen] = useState(false);

  const loadData = useCallback(() => {
    setLoadBal(true); setLoadReq(true);
    leaveAPI.getMyBalances().then(r => setBalances(toArr(r))).catch(() => {}).finally(() => setLoadBal(false));
    leaveAPI.getMyRequests().then(r => setMyReqs(toArr(r))).catch(() => {}).finally(() => setLoadReq(false));
    if (leaveAPI.getTypes) leaveAPI.getTypes().then(r => setTypes(toArr(r))).catch(() => {});

    if (isManager) {
      setLoadAll(true);
      if(isHR) {
        leaveAPI.listAll().then(r => setAll(toArr(r))).catch(() => {}).finally(() => setLoadAll(false));
      } else {
        leaveAPI.getManagerInbox().then(r => setAll(toArr(r))).catch(() => {}).finally(() => setLoadAll(false));
      }
    } else { setLoadAll(false); }
  }, [isManager, isHR]);

  useEffect(() => { loadData(); }, [loadData]);

  // ─── HANDLERS MATCHED TO JOI SCHEMAS ───

  const handleSubmit = async (payload) => {
    setSubmitting(true);
    try {
      await leaveAPI.submit(payload);
      toast.success('Leave request submitted!');
      setIsSubmitModalOpen(false);
      setTab('history');
      loadData();
    } catch (err) { toast.error(err.response?.data?.message || err.response?.data?.error || 'Submit Failed.'); } 
    finally { setSubmitting(false); }
  };

  const handleUpdate = async (formData) => {
    setSubmitting(true);
    try {
      await leaveAPI.updateRequest(editingRequest.LeaveRequestID || editingRequest.id, formData);
      toast.success('Request updated!');
      setEditingRequest(null);
      loadData();
    } catch (err) { toast.error(err.response?.data?.message || 'Update Failed'); } 
    finally { setSubmitting(false); }
  };

  const handleAction = async (id, action, reason) => {
    try {
      if (action === 'cancel') {
        if (!reason) { setReasonModal({ id, action: 'cancel' }); return; }

        // FIXED PAYLOAD: Joi schema enforces .min(5) characters. Pads the reason safely.
        let safeReason = reason;
        if (safeReason.length < 5) safeReason += " (Cancellation)"; 

        await leaveAPI.cancel(id, { CancelReason: safeReason });
        toast.success('Request cancelled');

      } else if (action === 'approve') {
        // FIXED PAYLOAD: Joi expects action verbs exactly.
        await leaveAPI.approveReject(id, { decision: 'APPROVED', comments: '' });
        toast.success('Request approved');

      } else if (action === 'reject') {
        if (!reason) { setReasonModal({ id, action: 'reject' }); return; }
        // FIXED PAYLOAD: Joi expects action verbs exactly.
        await leaveAPI.approveReject(id, { decision: 'REJECTED', comments: reason });
        toast.success('Request rejected');
      }
      loadData();
    } catch (err) { toast.error(err.response?.data?.message || err.response?.data?.error || 'Action failed'); }
  };

  const handleReasonConfirm = async (reason) => {
    setActingReason(true);
    try {
      await handleAction(reasonModal.id, reasonModal.action, reason);
      setReasonModal(null);
    } finally { setActingReason(false); }
  };

  const handlePayrollSync = async () => {
    try {
      // FIXED PAYLOAD: Sync expects periodYear and periodMonth strictly
      const payload = { periodYear: new Date().getFullYear(), periodMonth: new Date().getMonth() + 1 };
      const res = await leaveAPI.syncPayroll(payload);
      toast.success(`Synced leave records to payroll`);
    } catch (err) { toast.error(err.response?.data?.message || "Payroll sync failed."); }
  };

  const handleDelegate = async (id, payload) => {
    try {
      await leaveAPI.delegate(id, payload);
      toast.success("Delegation applied.");
    } catch(err) { toast.error(err.response?.data?.message || "Failed to set delegation"); }
  };

  const handleOverride = async (requestId, newStatus, reason) => {
    try {
      // Mapped exactly to APPROVED / REJECTED for Joi
      await leaveAPI.approveReject(requestId, { decision: newStatus, comments: reason });
      toast.success(`Request overridden to ${newStatus}`);
      loadData();
    } catch (err) { toast.error(err.response?.data?.message || 'Override failed'); }
  };

  const TABS = [
    { id: 'dashboard', label: 'Dashboard',    icon: BarChart2 },
    { id: 'history',   label: 'My History',   icon: Clock },
    ...(isManager ? [ { id: 'all', label: isHR ? 'Company Requests' : 'Team Inbox', icon: Users } ] : []),
    ...(isHR ? [ { id: 'settings', label: 'Settings', icon: Settings } ] : []),
  ];

  return (
    <>
      {reasonModal && <ReasonModal title={reasonModal.action === 'cancel' ? 'Cancel Request' : 'Reject Request'} placeholder={reasonModal.action === 'cancel' ? 'Min 5 chars...' : 'Reason for rejection...'} onConfirm={handleReasonConfirm} onClose={() => setReasonModal(null)} loading={actingReason} />}
      {editingRequest && <EditRequestModal req={editingRequest} leaveTypes={leaveTypes} onSave={handleUpdate} onClose={() => setEditingRequest(null)} loading={submitting} />}

      {isSubmitModalOpen && (
        <div style={{ position: 'fixed', top:0, left:0, right:0, bottom:0, background:'rgba(0,0,0,0.5)', zIndex: 1000, display: 'flex', justifyContent: 'center', alignItems: 'center' }}>
          <div className="card" style={{ width: '100%', maxWidth: 600, maxHeight: '90vh', overflowY: 'auto' }}>
            <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between' }}>
               <div className="card-title">Submit Leave Request</div>
               <button className="btn btn-ghost" onClick={() => setIsSubmitModalOpen(false)}><X size={18}/></button>
            </div>
            <SubmitLeaveForm leaveTypes={leaveTypes} onSubmit={handleSubmit} loading={submitting} />
          </div>
        </div>
      )}

      <div className="page-header" style={{ display: 'flex', justifyContent: 'space-between', padding: '1rem' }}>
        <div><h1>Leave Management</h1><p>Manage leave requests, balances, and approvals</p></div>
        <button className="btn btn-primary" onClick={() => setIsSubmitModalOpen(true)}><Plus size={18} style={{ marginRight: 8, verticalAlign: 'middle' }} /> New Request</button>
      </div>

      <div className="tabs" style={{ padding: '0 1rem' }}>
        {TABS.map(({ id, label, icon: Icon }) => (
          <button key={id} className={`tab-btn ${tab === id ? 'active' : ''}`} onClick={() => setTab(id)}><Icon size={14} style={{ marginRight: 6, verticalAlign: 'middle' }} />{label}</button>
        ))}
      </div>

      <div style={{ padding: '1rem' }}>
        {tab === 'dashboard' && (
          <div className="grid-4" style={{ marginBottom: 28 }}>
            {loadBal ? <SkeletonCard /> : balances.length === 0 ? <div style={{ padding: 20 }}>No Balances Found</div> : balances.map((b, i) => <BalanceCard key={i} balance={b} loading={false} />)}
          </div>
        )}

        {tab === 'history' && (
          <div className="card">
            <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between' }}>
              <div className="card-title">My Leave History</div>
              <div style={{ display: 'flex', gap: '10px' }}>
                 <select className="form-select" value={historyFilter} onChange={(e) => setHistoryFilter(e.target.value)} style={{ padding: '4px 8px' }}>
                   {STATUS_HISTORY.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                 </select>
                 <button className="btn btn-ghost btn-sm" onClick={loadData}><RefreshCw size={14}/></button>
              </div>
            </div>
            {loadReq ? <SkeletonCard /> : myRequests.filter(r => statusMatches(r.Status || r.status, historyFilter)).length === 0 ? <div style={{ padding: 20, textAlign: 'center' }}>No requests found</div> : (
              <div className="table-wrap">
                <table>
                  <thead><tr><th>Type</th><th>Period</th><th>Days</th><th>Status</th><th>Actions</th></tr></thead>
                  <tbody>{myRequests.filter(r => statusMatches(r.Status || r.status, historyFilter)).map((req, i) => <RequestRow key={i} req={req} onAction={handleAction} onEdit={setEditingRequest} isManager={false} />)}</tbody>
                </table>
              </div>
            )}
          </div>
        )}

        {tab === 'all' && isManager && (
          <div className="card">
            <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between' }}>
              <div className="card-title">{isHR ? 'Company-Wide Leaves' : 'Team Pending Approvals'}</div>
              <div style={{ display: 'flex', gap: '10px' }}>
                 <select className="form-select" value={allFilter} onChange={(e) => setAllFilter(e.target.value)} style={{ padding: '4px 8px' }}>
                   {STATUS_OPTIONS.map(opt => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
                 </select>
                 <button className="btn btn-ghost btn-sm" onClick={loadData}><RefreshCw size={14}/></button>
              </div>
            </div>
            {loadAll ? <SkeletonCard /> : allRequests.filter(r => statusMatches(r.Status || r.status, allFilter)).length === 0 ? <div style={{ padding: 20, textAlign: 'center' }}>No requests found</div> : (
              <div className="table-wrap">
                <table>
                  <thead><tr><th>Type</th><th>Employee</th><th>Period</th><th>Days</th><th>Status</th><th>Reason</th><th>Actions</th></tr></thead>
                  <tbody>{allRequests.filter(r => statusMatches(r.Status || r.status, allFilter)).map((req, i) => <RequestRow key={i} req={req} onAction={handleAction} isManager={true} isHR={isHR} />)}</tbody>
                </table>
              </div>
            )}
          </div>
        )}

        {tab === 'settings' && isHR && (
          <div className="grid-2">
             <div className="card">
               <div className="card-header"><div className="card-title"><ArrowRightLeft size={16} style={{marginRight:6}}/> Payroll Integration</div></div>
               <p style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', marginBottom: 16 }}>Synchronize all approved leave records with the payroll module to apply unpaid leave deductions.</p>
               <button className="btn btn-primary" onClick={handlePayrollSync}><RefreshCw size={14} style={{marginRight:6}}/> Sync to Payroll</button>
             </div>
             <OverridePanel requests={allRequests} onOverride={handleOverride} />
             <DelegationPanel onDelegate={handleDelegate} />
          </div>
        )}
      </div>
    </>
  );
}
